/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements template rendering per notification type, recipient validation,
 * and a pluggable transport layer (defaults to in-memory for testing).
 *
 * The adapter conforms to the NotificationAdapter interface and is registered
 * with NotificationService via registerAdapter().
 */

import type { NotificationPayload, NotificationType } from '../models/notification.js';
import type { NotificationAdapter, DeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered email ready for transport.
 */
export interface RenderedEmail {
  from: string;
  to: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport function signature — abstracts the actual email sending mechanism.
 * Return a messageId on success, or throw on failure.
 */
export type EmailTransport = (email: RenderedEmail) => Promise<string>;

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address (e.g., "noreply@taskflow.com"). */
  fromAddress: string;
  /** Optional: email provider API key. */
  apiKey?: string;
  /** Optional: email provider endpoint. */
  endpoint?: string;
  /** Optional: custom transport function. If not provided, uses in-memory transport. */
  transport?: EmailTransport;
}

/** Default configuration for the email adapter. */
export const defaultEmailConfig: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflow.com',
};

/**
 * Email templates keyed by notification type.
 * Each template receives the payload and returns rendered HTML and plain text.
 */
type TemplateRenderer = (payload: NotificationPayload) => { html: string; text: string };

const templates: Record<NotificationType, TemplateRenderer> = {
  order_confirmation: (payload) => {
    const html = [
      '<h1>Order Confirmation</h1>',
      `<p>Hello,</p>`,
      `<p>${escapeHtml(payload.body)}</p>`,
      payload.metadata['orderId']
        ? `<p><strong>Order ID:</strong> ${escapeHtml(payload.metadata['orderId'])}</p>`
        : '',
      '<p>Thank you for your order!</p>',
    ].join('\n');

    const text = [
      'Order Confirmation',
      '',
      payload.body,
      payload.metadata['orderId'] ? `Order ID: ${payload.metadata['orderId']}` : '',
      '',
      'Thank you for your order!',
    ].join('\n');

    return { html, text };
  },

  order_status_update: (payload) => {
    const prevStatus = payload.metadata['previousStatus'] ?? 'unknown';
    const newStatus = payload.metadata['newStatus'] ?? 'unknown';

    const html = [
      '<h1>Order Status Update</h1>',
      `<p>Your order status has changed from <strong>${escapeHtml(prevStatus)}</strong> to <strong>${escapeHtml(newStatus)}</strong>.</p>`,
      payload.metadata['orderId']
        ? `<p><strong>Order ID:</strong> ${escapeHtml(payload.metadata['orderId'])}</p>`
        : '',
    ].join('\n');

    const text = [
      'Order Status Update',
      '',
      `Your order status has changed from ${prevStatus} to ${newStatus}.`,
      payload.metadata['orderId'] ? `Order ID: ${payload.metadata['orderId']}` : '',
    ].join('\n');

    return { html, text };
  },

  user_welcome: (payload) => {
    const html = [
      '<h1>Welcome to TaskFlow Pro!</h1>',
      `<p>${escapeHtml(payload.body)}</p>`,
      '<p>Get started by creating your first order.</p>',
    ].join('\n');

    const text = [
      'Welcome to TaskFlow Pro!',
      '',
      payload.body,
      '',
      'Get started by creating your first order.',
    ].join('\n');

    return { html, text };
  },

  user_updated: (payload) => {
    const html = [
      '<h1>Account Updated</h1>',
      `<p>${escapeHtml(payload.body)}</p>`,
    ].join('\n');

    const text = ['Account Updated', '', payload.body].join('\n');

    return { html, text };
  },
};

/**
 * Basic HTML escaping for template rendering.
 */
function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validate that a string looks like a valid email address.
 */
function isValidEmail(email: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

/**
 * Resolve the recipient from the payload.
 * Validates that the recipient is a valid email address.
 * Returns the resolved email or throws if invalid.
 */
function resolveRecipient(payload: NotificationPayload): string {
  const recipient = payload.recipient.trim();
  if (!recipient) {
    throw new Error('Recipient email is empty');
  }
  if (!isValidEmail(recipient)) {
    throw new Error(`Invalid recipient email address: ${recipient}`);
  }
  return recipient;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: RenderedEmail[] = [];
  private inMemoryTransport: EmailTransport;
  private transport: EmailTransport;

  constructor(private config: EmailAdapterConfig = defaultEmailConfig) {
    this.inMemoryTransport = async (email: RenderedEmail) => {
      this.sentEmails.push(email);
      return `msg-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    };
    this.transport = config.transport ?? this.inMemoryTransport;
  }

  /**
   * Render a notification payload into an email using the appropriate template.
   */
  renderTemplate(payload: NotificationPayload): RenderedEmail {
    const renderer = templates[payload.type];
    const { html, text } = renderer(payload);
    const to = resolveRecipient(payload);

    return {
      from: this.config.fromAddress,
      to,
      subject: payload.subject,
      html,
      text,
    };
  }

  /**
   * Send an email notification.
   *
   * Steps: validate recipient → render template → send via transport.
   */
  async send(payload: NotificationPayload): Promise<DeliveryResult> {
    this.logger.info(`Preparing email to ${payload.recipient}: "${payload.subject}"`);

    let rendered: RenderedEmail;
    try {
      rendered = this.renderTemplate(payload);
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Template rendering failed';
      this.logger.error(`Email preparation failed: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }

    try {
      const messageId = await this.transport(rendered);
      this.logger.info(`Email delivered: ${messageId} from ${rendered.from} to ${rendered.to}`);

      return {
        success: true,
        providerMetadata: {
          from: rendered.from,
          messageId,
        },
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Transport error';
      this.logger.error(`Email delivery failed: ${errorMessage}`);
      return { success: false, error: errorMessage };
    }
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): RenderedEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email records (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { EmailTransport } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date(),
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter({ fromAddress: 'noreply@taskflow.com' });
  });

  describe('send', () => {
    it('should successfully send a valid email', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.from).toBe('noreply@taskflow.com');
      expect(result.providerMetadata?.messageId).toBeDefined();
    });

    it('should record sent emails in-memory', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@taskflow.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
    });

    it('should fail for invalid email recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email address');
    });

    it('should fail for empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('empty');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: EmailTransport = async () => {
        throw new Error('SMTP connection refused');
      };
      const failAdapter = new EmailAdapter({
        fromAddress: 'noreply@taskflow.com',
        transport: failingTransport,
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should use custom transport when provided', async () => {
      const transportedEmails: string[] = [];
      const customTransport: EmailTransport = async (email) => {
        transportedEmails.push(email.to);
        return 'custom-msg-id';
      };
      const customAdapter = new EmailAdapter({
        fromAddress: 'custom@taskflow.com',
        transport: customTransport,
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerMetadata?.messageId).toBe('custom-msg-id');
      expect(transportedEmails).toEqual(['alice@example.com']);
    });
  });

  describe('template rendering', () => {
    it('should render order_confirmation template with HTML and text', () => {
      const rendered = adapter.renderTemplate(makePayload());

      expect(rendered.html).toContain('<h1>Order Confirmation</h1>');
      expect(rendered.html).toContain('Order ID:');
      expect(rendered.html).toContain('Thank you for your order!');
      expect(rendered.text).toContain('Order Confirmation');
      expect(rendered.text).toContain('Order ID: order-1');
    });

    it('should render order_status_update template', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: order-1',
          body: 'Your order status has changed from pending to confirmed.',
          metadata: {
            orderId: 'order-1',
            previousStatus: 'pending',
            newStatus: 'confirmed',
          },
        }),
      );

      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.html).toContain('pending');
      expect(rendered.html).toContain('confirmed');
      expect(rendered.text).toContain('pending');
      expect(rendered.text).toContain('confirmed');
    });

    it('should render user_welcome template', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'user_welcome',
          subject: 'Welcome!',
          body: 'Welcome to TaskFlow Pro, Alice!',
          metadata: {},
        }),
      );

      expect(rendered.html).toContain('Welcome to TaskFlow Pro!');
      expect(rendered.html).toContain('Get started');
      expect(rendered.text).toContain('Welcome to TaskFlow Pro!');
    });

    it('should render user_updated template', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          type: 'user_updated',
          subject: 'Account Updated',
          body: 'Your account details have been updated.',
          metadata: {},
        }),
      );

      expect(rendered.html).toContain('Account Updated');
      expect(rendered.text).toContain('Your account details have been updated.');
    });

    it('should escape HTML in template rendering', () => {
      const rendered = adapter.renderTemplate(
        makePayload({
          body: 'Items: <script>alert("xss")</script>',
        }),
      );

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });

    it('should set correct from address', () => {
      const customAdapter = new EmailAdapter({ fromAddress: 'orders@taskflow.com' });
      const rendered = customAdapter.renderTemplate(makePayload());

      expect(rendered.from).toBe('orders@taskflow.com');
    });
  });

  describe('recipient resolution', () => {
    it('should trim whitespace from recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '  alice@example.com  ' }));

      expect(result.success).toBe(true);
      const sent = adapter.getSentEmails();
      expect(sent[0]?.to).toBe('alice@example.com');
    });

    it('should reject recipient with spaces', async () => {
      const result = await adapter.send(makePayload({ recipient: 'alice @example.com' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email');
    });

    it('should reject recipient without domain', async () => {
      const result = await adapter.send(makePayload({ recipient: 'alice@' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email');
    });
  });

  describe('clearSentEmails', () => {
    it('should clear all recorded emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('channel property', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });
});
